INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-57f41407-moex-00046', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「這場戰爭可能也是史上資訊戰火最猛烈的戰事。烏克蘭結合網紅群組、 各國行銷團隊的相助，發動掃雷犬的可愛照片、虛構飛行員的英勇故事； 俄羅斯方面則砸下超過 2021 年同期三倍的宣傳預算，展開媒體上的政治 宣傳，也僱用網紅拍攝造假影片、製作澤倫斯基的投降畫面。兩方在社群 平臺上交戰，真假帳號在其下留言、分享、按讚，搶奪訊息的主導權。」 根據上文，下列選項正確的是：', '["受到科技進步的影響，資訊戰成為決定勝敗的主要關鍵", "交戰國製作宣傳影片，目的是想讓世人瞭解戰爭的真相", "現代戰爭的交戰模式，包含透過社群平臺取得世人認同", "透過社群或行銷團隊，有助於交戰雙方判斷戰況的走向"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00047', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '賈伯斯在回顧自己面試員工的情境時說過：「在面試的過程中我會多次故 意讓面試者感到心煩意亂，例如批評他們之前的工作，並對他們說：『那 真是一個沒用的產品，你為什麼要從事那項工作呢？』我想看看在面臨壓 力的情況下，他們會有什麼表現。他們是否會屈服，他們是否會對自己曾 經做過的事情持有堅定的信念、信仰和自豪感。」 根據上文，下列選項何者符合賈伯斯用人的看法？', '["參加面試者是否具有主動爭取的動力", "選拔出來的人是否能面對強大的壓力", "聘用比自己強的人來帶動公司的蛻變", "選擇是否有批判與創新思維的面試者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00048', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「美國史丹佛大學提出2025年的『開放環形大學』願景，打破大學學制， 校園裡將會混雜著各種年齡和經驗的學生，彼此共同學習。大學本身也會 因為隨時有著『在學生』正在不同的企業、機構任職，學校將可以連結更 多的資源和平臺。未來，當有人問：『你主修什麼？』學生不會說：『我 主修生物』，而是回答：『我在學生物學，我希望以後可以減少世界饑荒 的問題。』」 根據上文，在史丹佛大學的願景中，下列選項何者最不可能出現？', '["你的科系觀念淡薄，跨領域修課很正常", "你可以同時擁有在學生與職場員工身分", "你不再迷信名校，讀那所大學沒有差別", "你的爸媽也很有可能成為你的大學同學"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00049', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「邵族是原住民山區人口最少數的一族，聚居於南投縣日月潭及雨社山一 帶。相傳邵族的祖先是追逐白鹿翻越『阿里山』而來。因為和漢族接觸較 早，也曾被歸類為平埔族，但該族到底是屬於『高山族』或者是『平埔族』 學界並無定見。雖然邵族文化早期便與外族接觸，但至今仍維持嚴謹的祖 靈信仰。生活中，同時也信仰漢族道教或西方基督教，呈現多元宗教信仰 平行存在的現象。」 根據上文，下列選項何者正確？', '["邵族是平埔族的分支", "邵族的居住地以平地為主", "邵族最早的起源來自阿里山", "邵族的信仰呈現多元化的現象"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00050', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「自我個體中沒有對立、衝突，在生命自覺中達到自我生命的和諧，這是 『禮』。禮的和諧前提，有一個重要的、不可缺少的元素，在於對生命的 認識、生命的覺醒。『分寸』即所謂的『適當』，得體是禮的一個重要的 核心。而這核心是在於生命的自覺。以至於每件事，它的適當分寸在那裡， 它最恰到好處的是什麼。這要經過我們自己的觀察、理解、分析、綜合之 後，再做判斷。」 根據上文，下列選項最符合作者觀點的是：', '["透過生命自覺，掌握分寸並有清明判斷，有助達到自我生命的和諧", "落實禮可由外而內，先強調言行得體適當，再追求內在生命之覺醒", "為化解對立衝突，促進社會和諧，人應致力達到理性與感性的平衡", "禮能讓不同階級與各行各業的人知道行事之分寸，以恢復尊卑倫理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00051', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於管轄，下列敘述何者正確？', '["訴訟由原告住所地法院管轄", "民事訴訟法並無專屬管轄的規定", "當事人不得為合意管轄之約定", "當事人不得以合意定第二審管轄法院"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00052', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '甲主張乙妨害其名譽，向臺灣臺北地方法院起訴請求乙賠償新臺幣 30 萬 元，由該院簡易庭法官A審理。嗣於言詞辯論期日，甲當場以言詞聲請A 迴避。關於法官迴避，下列敘述何者正確？', '["本件訴訟行簡易訴訟程序，由獨任法官審理。但本件法官迴避之聲請， 仍應由臺灣臺北地方法院以合議裁定之", "因聲請法官迴避，應舉其原因，並自聲請之日起，於3日內釋明之，甲 不得於言詞辯論期日以言詞聲請法官迴避", "於迴避之聲請事件終結前，本件訴訟雖不得辯論終結，但該被聲請迴避 之法官仍得調查證據", "如甲係以 A 駁回其證據調查之聲請，足認 A 執行職務有偏頗之虞為由 聲請迴避時，A即應停止訴訟程序，不得以甲係意圖延滯訴訟而仍辯論 終結本件訴訟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00053', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', 'A公益社團法人章程係以協助受職業傷害勞工為宗旨，A之社員甲、乙、 丙先前均任職丁公司，甲、乙、丙主張在丁公司任職期間，因丁公司管理 不當，其等受有健康權、身體權之損害。甲、乙、丙選定A為其3人起訴 請求丁為金錢賠償，下列何者與民事訴訟法規定不符？', '["甲撤回選定時，對乙、丙之選定不生影響", "法院得依甲、乙、丙之言詞表明願由法院判命丁給付賠償總額，為賠償 總額之裁判", "當事人之選定及其更換、增減，應以文書證之", "甲、乙、丙得限制A為捨棄、認諾、撤回或和解"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00054', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '下列何者為訴訟代理權消滅？', '["原委任該訴訟代理人之當事人聲明終止委任並已通知他造", "原委任該訴訟代理人之當事人於訴訟進行中死亡", "原委任該訴訟代理人之當事人於訴訟進行中經法院為破產宣告", "原委任該訴訟代理人之當事人於訴訟進行中經法院為輔助宣告"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00055', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '下列何種異議即使有理由，異議人仍不能聲請退還已繳之裁判費？', '["對於司法事務官之處分提出異議", "對於法院書記官之處分提出異議", "不得上訴第三審法院之事件，第二審所為對證人處以罰鍰之裁定", "不得上訴第三審法院之事件，第二審命強制提出文書之裁定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
